SQLLite.SQL:
                INSERT INTO MCOL_DATA M     
                (   M.CLAIM_NUMBER         
                ,	M.DEFT_ID              
                ,	M.TYPE                                                                
                ,	M.EVENT_DATE           
                ,	M.REJECT_CODE          
                ,	M.WARRANT_NUMBER       
                ,	M.RETURN_CODE          
                ,	M.RETURN_INFO          
                ,	M.ADDR_1               
                ,	M.ADDR_2               
                ,	M.ADDR_3               
                ,	M.ADDR_4               
                ,	M.ADDR_5               
                ,	M.POSTCODE             
                ,	M.DATE_SENT
				,	M.PREVIOUS_CREDITOR
				,	M.NEW_CREDITOR
				,	M.JUDGMENT_TYPE
				,	M.JOINT_JUDGMENT
				,	M.TOTAL
				,	M.INSTALMENT_AMOUNT
				,	M.FREQUENCY
				,	M.FIRST_PAYMENT_DATE
				,	M.MCOL_REFERENCE
				,	M.JUDGMENT_REFERENCE
				,	M.PAID_DATE
                ) VALUES                   
                (    ${param.claimNumber}  
                ,    ${param.deftId}       
                ,    ${param.type}         
                ,    TO_DATE(${param.eventDate}, 'YYYY-MM-DD')
                ,    ${param.rejectCode}   
                ,    ${param.warrantNumber}
                ,    ${param.returnCode}   
                ,    ${param.returnInfo}   
                ,    ${param.addr1}        
                ,    ${param.addr2}        
                ,    ${param.addr3}        
                ,    ${param.addr4}        
                ,    ${param.addr5}        
                ,    ${param.postcode}     
                ,    TO_DATE(${param.dateSent}, 'YYYY-MM-DD')
				,    ${param.prevCred}
				,    ${param.newCred}
				,    ${param.judgType}
				,    ${param.jointJudg}
				,    ${param.total}
				,    ${param.instalAmount}
				,    ${param.frequency}
				,    TO_DATE(${param.firstPaymentDate}, 'YYYY-MM-DD')
				,    ${param.mcolRef}
				,    ${param.judgRef}
				,	 TO_DATE(${param.paidInFull}, 'YYYY-MM-DD')
                )
